{"code":"import json

def clean_id(i):
    if i is None: return None
    s = str(i).strip()
    if s.lower() == 'none': return None
    if s == '': return None
    return s.lstrip('#')

# Load data
with open(locals()['var_function-call-804297705162023277'], 'r') as f:
    contracts = json.load(f)
with open(locals()['var_function-call-804297705162024456'], 'r') as f:
    opportunities = json.load(f)
with open(locals()['var_function-call-804297705162025635'], 'r') as f:
    line_items = json.load(f)
price_entries = locals()['var_function-call-804297705162026814']

# Date range
start_date = "2022-06-25"
end_date = "2022-11-25"

eligible_contract_ids = set()
for c in contracts:
    c_date = c.get('CompanySignedDate')
    if c_date:
        c_date = c_date.strip()
        # Ensure date format is YYYY-MM-DD
        if len(c_date) >= 10:
             c_date = c_date[:10]
             if start_date <= c_date <= end_date:
                cid = clean_id(c.get('Id'))
                if cid:
                    eligible_contract_ids.add(cid)

# Filter opportunities
opp_owner_map = {}
for o in opportunities:
    cont_id = clean_id(o.get('ContractID__c'))
    if cont_id and cont_id in eligible_contract_ids:
        oid = clean_id(o.get('Id'))
        owner = clean_id(o.get('OwnerId'))
        if oid and owner:
            opp_owner_map[oid] = owner

# Price map
price_map = {}
for p in price_entries:
    pid = clean_id(p.get('Id'))
    u_price = p.get('UnitPrice')
    if pid and u_price:
        try:
            price_map[pid] = float(u_price)
        except:
            pass

# Calculate sales
agent_sales = {}
for item in line_items:
    oid = clean_id(item.get('OpportunityId'))
    if oid in opp_owner_map:
        owner = opp_owner_map[oid]
        pid = clean_id(item.get('PricebookEntryId'))
        qty = item.get('Quantity')

        if pid in price_map and qty:
            try:
                amount = float(qty) * price_map[pid]
                agent_sales[owner] = agent_sales.get(owner, 0.0) + amount
            except:
                pass

# Find top agent
top_agent = None
max_sales = -1.0

for agent, sales in agent_sales.items():
    if sales > max_sales:
        max_sales = sales
        top_agent = agent

print("__RESULT__:")
print(json.dumps(top_agent))"}
